code = """import json, pandas as pd, re

def load_records(x):
    if isinstance(x, str):
        with open(x, 'r', encoding='utf-8') as f:
            return json.load(f)
    return x

books = load_records(var_call_c6ejVzLZGUJ7lYwUAS47o2xi)
reviews = load_records(var_call_6USzYgs9evMZEgx21rLOaur9)

bdf = pd.DataFrame(books)
rdf = pd.DataFrame(reviews)

# parse year from details
year_pat = re.compile(r'\b(19\d{2}|20\d{2})\b')

def extract_year(s):
    if not isinstance(s, str):
        return None
    # prefer years near keywords
    low = s.lower()
    # try patterns like 'released on' or 'published on' followed by date containing year
    # but simplest: take first year occurrence
    m = year_pat.search(s)
    if m:
        y = int(m.group(1))
        if 1500 <= y <= 2100:
            return y
    return None

bdf['year'] = bdf['details'].map(extract_year)
# join purchaseid_XXX -> bookid_XXX
rdf['book_id'] = rdf['purchase_id'].astype(str).str.replace('purchaseid_', 'bookid_', regex=False)
rdf['rating'] = pd.to_numeric(rdf['rating'], errors='coerce')

j = rdf.merge(bdf[['book_id','year']], on='book_id', how='inner')
j = j.dropna(subset=['year','rating'])
j['decade_start'] = (j['year']//10)*10

# distinct books per decade among rated books
books_per_decade = j.groupby('decade_start')['book_id'].nunique().rename('n_books')
ratings_per_decade = j.groupby('decade_start')['rating'].mean().rename('avg_rating')
summary = pd.concat([books_per_decade, ratings_per_decade], axis=1).reset_index()
summary = summary[summary['n_books']>=10]
if summary.empty:
    ans = None
else:
    top = summary.sort_values(['avg_rating','n_books'], ascending=[False, False]).iloc[0]
    decade_label = f"{int(top['decade_start'])}s"
    ans = decade_label

print('__RESULT__:')
print(json.dumps({'decade': ans}))"""

